#!/usr/bin/env bash
set -euo pipefail

ROOT_DIR="$(git rev-parse --show-toplevel 2>/dev/null || pwd)"
TARGET_DIR="$ROOT_DIR/docs/01-product"
PROTOTYPE_FILE="$TARGET_DIR/claude-prototype-inventory.csv"
ROUTE_FILE="$TARGET_DIR/claude-route-canonicalization.csv"

mkdir -p "$TARGET_DIR"

cat <<'B64' | base64 -d | gzip -dc > "$PROTOTYPE_FILE"

B64

cat <<'B64' | base64 -d | gzip -dc > "$ROUTE_FILE"

B64

prototype_lines="$(wc -l < "$PROTOTYPE_FILE" | tr -d ' ')"
route_lines="$(wc -l < "$ROUTE_FILE" | tr -d ' ')"

[[ "$prototype_lines" == "316" ]] || { echo "Expected 316 prototype inventory lines, got $prototype_lines" >&2; exit 1; }
[[ "$route_lines" == "106" ]] || { echo "Expected 106 route inventory lines, got $route_lines" >&2; exit 1; }

grep -q '^source_path,screen_name,artifact_class' "$PROTOTYPE_FILE"
grep -q '^surface,route,domain,owner_module' "$ROUTE_FILE"

echo "Installed canonicalization inventories:"
echo "- $PROTOTYPE_FILE ($prototype_lines lines)"
echo "- $ROUTE_FILE ($route_lines lines)"
